import{_ as a,o,c as t,a0 as n}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"NEXUS Canonical T4 вҖ” Grafo Multi-Relacional de NavegaГ§ГЈo TopolГіgica","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_T4.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_T4.md","lastUpdated":1782593311000}'),s={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_T4.md"};function i(r,e,d,c,l,p){return o(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="nexus-canonical-t4-вҖ”-grafo-multi-relacional-de-navegacao-topologica" tabindex="-1">NEXUS Canonical T4 вҖ” Grafo Multi-Relacional de NavegaГ§ГЈo TopolГіgica <a class="header-anchor" href="#nexus-canonical-t4-вҖ”-grafo-multi-relacional-de-navegacao-topologica" aria-label="Permalink to &quot;NEXUS Canonical T4 вҖ” Grafo Multi-Relacional de NavegaГ§ГЈo TopolГіgica&quot;">вҖӢ</a></h1><h2 id="proposito" tabindex="-1">PropГіsito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;PropГіsito&quot;">вҖӢ</a></h2><p>Este documento define o T4 em seu estado atual como <strong>grafo multi-relacional em produГ§ГЈo</strong> вҖ” camada de navegaГ§ГЈo topolГіgica que conecta arquivos e chunks por 4 tipos de aresta, organizados em 3 eixos de projeГ§ГЈo. Ele substitui a versГЈo anterior que subestimava o papel do T4 como mero estГЎgio intermediГЎrio.</p><p>O T4 nГЈo Г© uma visГЈo futura nem um experimento. Гү o grafo que os agentes navegam hoje via <code>nexus_adjacent()</code> para expandir contexto, cruzar dependГӘncias e descobrir relaГ§Гөes estruturais e semГўnticas.</p><p>Para a especificaГ§ГЈo detalhada das arestas, consulte: <a href="./T4_GRAPH_NORMS.html"><code>T4_GRAPH_NORMS.md</code></a>.</p><hr><h2 id="o-que-o-t4-e-hoje" tabindex="-1">O que o T4 Г© hoje <a class="header-anchor" href="#o-que-o-t4-e-hoje" aria-label="Permalink to &quot;O que o T4 Г© hoje&quot;">вҖӢ</a></h2><p>O T4 Г© um <strong>hipergrafo multi-relacional</strong> persistido em PostgreSQL (<code>links</code>), alimentado por:</p><ul><li><strong>part_of</strong> вҖ” hierarquia fileвҶ’chunk (extraГ§ГЈo estrutural do pipeline de ingestГЈo)</li><li><strong>depends_on:imports</strong> вҖ” dependГӘncias entre arquivos (extraГӯdas de imports TypeScript, Rust, Python, SQL)</li><li><strong>semantic_bridge</strong> вҖ” similaridade semГўntica entre summaries de file nodes</li><li><strong>contradicts</strong> вҖ” contradiГ§Гөes detectadas entre chunks semanticamente incompatГӯveis</li></ul><p>O ponto de entrada estrutural Г© o <strong>file node</strong> (level=4). Todo chunk pertence a exatamente um file node via <code>part_of</code>. A navegaГ§ГЈo cross-file ocorre exclusivamente no nГӯvel de file nodes; chunks de arquivos diferentes nГЈo tГӘm arestas diretas.</p><h3 id="metricas-atuais" tabindex="-1">MГ©tricas atuais <a class="header-anchor" href="#metricas-atuais" aria-label="Permalink to &quot;MГ©tricas atuais&quot;">вҖӢ</a></h3><table tabindex="0"><thead><tr><th>Tipo</th><th>Quantidade</th></tr></thead><tbody><tr><td>File nodes (level=4)</td><td>899</td></tr><tr><td>Chunks (levels 0+1+2)</td><td>38.566</td></tr><tr><td><code>part_of</code></td><td>38.060</td></tr><tr><td><code>depends_on:imports</code></td><td>295</td></tr><tr><td><code>semantic_bridge</code></td><td>176</td></tr><tr><td><code>contradicts</code></td><td>119</td></tr></tbody></table><hr><h2 id="os-4-tipos-de-aresta-criteria" tabindex="-1">Os 4 tipos de aresta (criteria) <a class="header-anchor" href="#os-4-tipos-de-aresta-criteria" aria-label="Permalink to &quot;Os 4 tipos de aresta (criteria)&quot;">вҖӢ</a></h2><table tabindex="0"><thead><tr><th>Criteria</th><th>DireГ§ГЈo</th><th>Origem</th><th>Natureza</th></tr></thead><tbody><tr><td><code>part_of</code></td><td>chunk вҶ’ file (inbound)</td><td>Pipeline de ingestГЈo</td><td>HierГЎrquica вҖ” fato</td></tr><tr><td><code>depends_on:imports</code></td><td>A вҶ’ B (A importa B)</td><td>Parser de imports (TS, Rust, Python, SQL)</td><td>Estrutural вҖ” fato</td></tr><tr><td><code>semantic_bridge</code></td><td>Bidirecional simГ©trica</td><td>Similaridade de embeddings (threshold 0.80)</td><td>SemГўntica вҖ” aproximaГ§ГЈo</td></tr><tr><td><code>contradicts</code></td><td>Bidirecional simГ©trica</td><td>Pipeline de enriquecimento</td><td>Conflito вҖ” aproximaГ§ГЈo</td></tr></tbody></table><p>Cada criteria projeta um <strong>Гўngulo de visГЈo</strong> diferente sobre o mesmo sistema. Um mesmo par de nГіs pode ter mГәltiplas arestas de criteria diferentes.</p><hr><h2 id="os-3-eixos-de-projecao" tabindex="-1">Os 3 eixos de projeГ§ГЈo <a class="header-anchor" href="#os-3-eixos-de-projecao" aria-label="Permalink to &quot;Os 3 eixos de projeГ§ГЈo&quot;">вҖӢ</a></h2><p>Toda navegaГ§ГЈo no T4 Г© uma <strong>fatia</strong> tridimensional:</p><table tabindex="0"><thead><tr><th>Eixo</th><th>Valores</th><th>Exemplo</th></tr></thead><tbody><tr><td><code>criteria</code></td><td><code>part_of</code>, <code>depends_on:imports</code>, <code>semantic_bridge</code>, <code>contradicts</code></td><td>SГі dependГӘncias estruturais</td></tr><tr><td><code>file_type</code></td><td><code>typescript</code>, <code>sql</code>, <code>markdown</code>, <code>python</code>, <code>json</code>, <code>rust</code>, <code>yaml</code></td><td>SГі TypeScript</td></tr><tr><td><code>project</code></td><td><code>nexus</code>, <code>intraclinica-ng</code></td><td>SГі intraclinica</td></tr></tbody></table><p>Fatia composta tГӯpica:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>criteria=depends_on:imports + file_type=typescript + project=intraclinica-ng</span></span>
<span class="line"><span>вҶ’ &quot;dependГӘncias entre arquivos TypeScript do frontend&quot;</span></span></code></pre></div><hr><h2 id="anatomia-do-grafo-esqueleto-carne-cartilagem" tabindex="-1">Anatomia do grafo: esqueleto, carne, cartilagem <a class="header-anchor" href="#anatomia-do-grafo-esqueleto-carne-cartilagem" aria-label="Permalink to &quot;Anatomia do grafo: esqueleto, carne, cartilagem&quot;">вҖӢ</a></h2><p>O T4 tem trГӘs camadas de rigidez, como um organismo biolГіgico:</p><table tabindex="0"><thead><tr><th>Camada</th><th>MetГЎfora</th><th>Arestas</th><th>Mutabilidade</th></tr></thead><tbody><tr><td><strong>RГӯgida</strong></td><td>Esqueleto</td><td><code>depends_on:imports</code></td><td>Fato вҖ” imutГЎvel. Se A importa B, a aresta existe.</td></tr><tr><td><strong>SemГўntica</strong></td><td>Carne</td><td><code>semantic_bridge</code>, <code>contradicts</code></td><td>AproximaГ§ГЈo вҖ” mutГЎvel com threshold/modelo.</td></tr><tr><td><strong>ClassificaГ§ГЈo</strong></td><td>Cartilagem</td><td><code>file_type</code>, <code>project</code></td><td>Metadado вҖ” classifica os nГіs, nГЈo as arestas.</td></tr></tbody></table><p><strong>Esqueleto:</strong> o agente confia cegamente em <code>depends_on:imports</code> para navegaГ§ГЈo estrutural.</p><p><strong>Carne:</strong> <code>semantic_bridge</code> Г© Гәtil para descoberta, mas admite falsos positivos. O agente usa como dica, nГЈo como fato.</p><p><strong>Cartilagem:</strong> os eixos <code>file_type</code> e <code>project</code> organizam os nГіs em categorias. O agente fatia o grafo para focar no formato relevante.</p><p>Regra de navegaГ§ГЈo: <strong>esqueleto primeiro, carne depois</strong> вҖ” caminhe por dependГӘncias estruturais antes de explorar pontes semГўnticas.</p><hr><h2 id="o-triangulo-t3-вҶ’-t4-вҶ’-l3" tabindex="-1">O triГўngulo T3 вҶ’ T4 вҶ’ L3 <a class="header-anchor" href="#o-triangulo-t3-вҶ’-t4-вҶ’-l3" aria-label="Permalink to &quot;O triГўngulo T3 вҶ’ T4 вҶ’ L3&quot;">вҖӢ</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T3 (Qdrant)            T4 (Grafo)              L3 (DomГӯnio)</span></span>
<span class="line"><span>в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ           в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ              в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ</span></span>
<span class="line"><span>busca semГўntica        expansГЈo topolГіgica     sГӯntese emergente</span></span>
<span class="line"><span>encontra sementes      caminha o grafo         cluster de domГӯnio</span></span>
<span class="line"><span>в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ           в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ            в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ</span></span>
<span class="line"><span>в”Ӯ  chunk   в”Ӯв”Җв”Җв”ҖT3в”Җв”Җв”Җв–¶  в”Ӯ file nodeв”Ӯв”Җв”Җв”ҖT4в”Җв”Җв”Җв”Җв–¶  в”Ӯ domГӯnio  в”Ӯ</span></span>
<span class="line"><span>в”Ӯ semente  в”Ӯ   query   в”Ӯ (level4) в”Ӯ  caminhada  в”Ӯ emergido в”Ӯ</span></span>
<span class="line"><span>в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ           в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ            в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ</span></span>
<span class="line"><span>     в”Ӯ                      в”Ӯ                       в–І</span></span>
<span class="line"><span>     в”Ӯ    nexus_query()     в”Ӯ   nexus_adjacent()    в”Ӯ</span></span>
<span class="line"><span>     в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ</span></span></code></pre></div><ol><li><strong>T3</strong> encontra sementes via busca semГўntica (<code>nexus_query</code>).</li><li><strong>T4</strong> expande topologicamente a partir do file node (<code>nexus_adjacent</code>).</li><li><strong>L3</strong> nГЈo existe mais como nГӯvel fixo no banco вҖ” <strong>emerge por detecГ§ГЈo de comunidades</strong> no grafo T4. O agente pode agrupar file nodes conectados por <code>depends_on:imports</code> + <code>semantic_bridge</code> e tratar o cluster como um domГӯnio coerente.</li></ol><p>A implicaГ§ГЈo prГЎtica: L3 nГЈo Г© armazenado como blob individual. Гү uma <strong>sГӯntese de domГӯnio</strong> que o agente materializa on-the-fly ao caminhar o T4 e identificar subgrafos densos.</p><hr><h2 id="padroes-de-navegacao" tabindex="-1">PadrГөes de navegaГ§ГЈo <a class="header-anchor" href="#padroes-de-navegacao" aria-label="Permalink to &quot;PadrГөes de navegaГ§ГЈo&quot;">вҖӢ</a></h2><h3 id="subir-chunk-вҶ’-file-node" tabindex="-1">Subir: chunk вҶ’ file node <a class="header-anchor" href="#subir-chunk-вҶ’-file-node" aria-label="Permalink to &quot;Subir: chunk вҶ’ file node&quot;">вҖӢ</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_query(&quot;...&quot;) вҶ’ obtГ©m node_id do chunk</span></span>
<span class="line"><span>nexus_adjacent(chunk) вҶ’ filtra outbound part_of вҶ’ file node (level=4)</span></span></code></pre></div><h3 id="descer-file-node-вҶ’-chunks" tabindex="-1">Descer: file node вҶ’ chunks <a class="header-anchor" href="#descer-file-node-вҶ’-chunks" aria-label="Permalink to &quot;Descer: file node вҶ’ chunks&quot;">вҖӢ</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_adjacent(file_node) вҶ’ inbound com criteria=part_of вҶ’ lista de chunks</span></span></code></pre></div><h3 id="cruzar-por-dependencia-file-вҶ’-file" tabindex="-1">Cruzar por dependГӘncia: file вҶ’ file <a class="header-anchor" href="#cruzar-por-dependencia-file-вҶ’-file" aria-label="Permalink to &quot;Cruzar por dependГӘncia: file вҶ’ file&quot;">вҖӢ</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_adjacent(file_node) вҶ’ outbound com criteria=depends_on:imports</span></span>
<span class="line"><span>вҶ’ arquivos importados pelo file atual</span></span></code></pre></div><h3 id="cruzar-por-semantica-file-вҶ’-file" tabindex="-1">Cruzar por semГўntica: file вҶ’ file <a class="header-anchor" href="#cruzar-por-semantica-file-вҶ’-file" aria-label="Permalink to &quot;Cruzar por semГўntica: file вҶ’ file&quot;">вҖӢ</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_adjacent(file_node) вҶ’ inbound/outbound com criteria=semantic_bridge</span></span>
<span class="line"><span>вҶ’ arquivos com summary similar</span></span></code></pre></div><h3 id="combinar-t3-t4-completo" tabindex="-1">Combinar: T3 + T4 completo <a class="header-anchor" href="#combinar-t3-t4-completo" aria-label="Permalink to &quot;Combinar: T3 + T4 completo&quot;">вҖӢ</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_query(&quot;...&quot;) вҶ’ chunk node_id</span></span>
<span class="line"><span>  вҶ’ adjacent(chunk) вҶ’ sobe (part_of) pro file node</span></span>
<span class="line"><span>  вҶ’ adjacent(file) вҶ’ cruza (depends_on) pra outros files</span></span>
<span class="line"><span>  вҶ’ adjacent(file) вҶ’ desce (part_of) pros chunks alvo</span></span></code></pre></div><hr><h2 id="direcao-canonica" tabindex="-1">DireГ§ГЈo canГҙnica <a class="header-anchor" href="#direcao-canonica" aria-label="Permalink to &quot;DireГ§ГЈo canГҙnica&quot;">вҖӢ</a></h2><p>O T4 Г© o grafo em produГ§ГЈo. Sua evoluГ§ГЈo segue estes princГӯpios:</p><ul><li><strong>File node (level=4) permanece como ponto de entrada estrutural.</strong> Toda navegaГ§ГЈo comeГ§a ou termina nele.</li><li><strong><code>depends_on:imports</code> Г© a espinha dorsal.</strong> Arestas estruturais sГЈo prioridade вҖ” sГЈo determinГӯsticas, confiГЎveis e independem de modelo.</li><li><strong><code>semantic_bridge</code> Г© complementar.</strong> Гҡtil para descoberta em territГіrio desconhecido; transitГіrio por natureza.</li><li><strong>L3 emerge, nГЈo Г© armazenado.</strong> A sГӯntese de domГӯnio Г© responsabilidade do agente via community detection, nГЈo um blob prГ©-computado.</li><li><strong>O triГўngulo T3вҶ’T4вҶ’L3 Г© o fluxo canГҙnico.</strong> Query semГўntica вҶ’ expansГЈo topolГіgica вҶ’ sГӯntese de domГӯnio.</li></ul><hr><h2 id="referencias" tabindex="-1">ReferГӘncias <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;ReferГӘncias&quot;">вҖӢ</a></h2><ul><li><a href="./T4_GRAPH_NORMS.html"><code>T4_GRAPH_NORMS.md</code></a> вҖ” EspecificaГ§ГЈo detalhada de tipos de aresta, regras de navegaГ§ГЈo e normas estruturais</li><li><a href="./../NEXUS Docs/CANONICAL_ARCHITECTURE.html"><code>CANONICAL_ARCHITECTURE.md</code></a> вҖ” SГӯntese arquitetural geral do NEXUS (camadas T1-T4)</li><li><a href="./../NEXUS Docs/CANONICAL_MEMORY_MODEL.html"><code>CANONICAL_MEMORY_MODEL.md</code></a> вҖ” PropГіsito e finalidade da memГіria operacional</li><li><a href="./../NEXUS Docs/CANONICAL_RUNTIME.html"><code>CANONICAL_RUNTIME.md</code></a> вҖ” Contrato operacional do runtime ativo</li></ul>`,54)])])}const h=a(s,[["render",i]]);export{m as __pageData,h as default};
